/**
 * SmartMenu Types
 * 
 * Defines the menu system that determines which drawers and menu items
 * are presented to the user based on their persona, app, and context.
 */

import type { AppId, AgentId } from '@/services/orchestration/flowContext';

// =============================================================================
// MENU ITEM TYPES
// =============================================================================

/** Menu item action types */
export type MenuItemAction =
  | 'openDrawer'
  | 'focusTab'
  | 'navigate'
  | 'openAgent'
  | 'openModal'
  | 'external'
  // Experience Laddering actions — Living Canon / 21 Sats
  // These map to MENU_ACTION bridge messages (ShellOutboundType) in iframe-bridge.
  // The Lovable thin client smart menu exposes these; platform smart menu must match.
  | 'vote'              // Open active election for eligible item
  | 'submitContribution' // Open guided submission shell (RuntimeCapsuleAdminEditor, democratised)
  | 'correspond'        // Open correspondent submission flow (requires knyt:correspondent entitlement)
  | 'viewProgress';     // Open Order of Metaiye progression panel

/** Menu item definition */
export interface MenuItem {
  id: string;
  label: string;
  icon?: string;
  action: MenuItemAction;
  targetId?: string;
  targetUrl?: string;
  shortcut?: string;
  badge?: {
    type: 'count' | 'dot' | 'text';
    value?: string | number;
    color?: 'primary' | 'warning' | 'error' | 'success';
  };
  children?: MenuItem[];
  visibilityRules?: MenuVisibilityRules;
  /** Extra context for Experience Laddering actions */
  ladderingContext?: {
    /** Election ID for 'vote' actions */
    electionId?: string;
    /** Branch target for 'submitContribution' / 'correspond' actions */
    branchTarget?: 'canon' | 'community' | 'correspondent';
    /** Contribution schema slug for 'submitContribution' actions */
    contributionSchema?: string;
    /** World ID (defaults to '21sats') */
    worldId?: string;
  };
}

/** Menu visibility rules */
export interface MenuVisibilityRules {
  allowedPersonas?: string[];
  requiredEntitlements?: string[];
  minReputationScore?: number;
  requiresAuth?: boolean;
  hideOnMobile?: boolean;
  hideOnDesktop?: boolean;
}

// =============================================================================
// MENU SECTION TYPES
// =============================================================================

/** Menu section (group of items) */
export interface MenuSection {
  id: string;
  label?: string;
  items: MenuItem[];
  visibilityRules?: MenuVisibilityRules;
}

// =============================================================================
// SMART MENU CONFIGURATION
// =============================================================================

/** Complete menu configuration for an app */
export interface SmartMenuConfig {
  id: string;
  appId: AppId;
  tenantId: string;
  personaId?: string;

  /** Primary navigation items (top-level) */
  primaryNav: MenuSection[];

  /** Secondary navigation (footer, settings) */
  secondaryNav?: MenuSection[];

  /** Quick actions (floating action buttons, etc.) */
  quickActions?: MenuItem[];

  /** Agent shortcuts */
  agentShortcuts?: AgentShortcut[];

  /** Drawer order (left to right) */
  drawerOrder?: string[];

  createdAt?: string;
  updatedAt?: string;
}

/** Agent shortcut in menu */
export interface AgentShortcut {
  agentId: AgentId;
  label: string;
  icon?: string;
  hotkey?: string;
  defaultOpen?: boolean;
}

// =============================================================================
// MENU STATE
// =============================================================================

/** Runtime menu state */
export interface MenuState {
  activeMenuItemId?: string;
  expandedSections: string[];
  openDrawerIds: string[];
  focusedDrawerId?: string;
  focusedTabId?: string;
  activeAgentId?: AgentId;
}

/** Menu state delta (for updates) */
export interface MenuStateDelta {
  activeMenuItemId?: string;
  expandedSections?: string[];
  openDrawerIds?: string[];
  focusedDrawerId?: string;
  focusedTabId?: string;
  activeAgentId?: AgentId;
}

// =============================================================================
// MENU CONTEXT
// =============================================================================

/** Context for menu rendering */
export interface MenuContext {
  appId: AppId;
  personaId: string;
  identityState: 'anon' | 'pseudo' | 'semi' | 'full';
  reputationScore?: number;
  entitlements?: string[];
  deviceType: 'mobile' | 'desktop' | 'tv';
}

export default {
  // Type exports only
};

/**
 * SmartDrawer / SmartMenu Type Definitions
 * 
 * The arrangement layer in the Smart Triad:
 * - SmartContentQube → what the content IS
 * - SmartWalletQube → what the user HAS/OWES/CAN EARN
 * - SmartDrawerManifest → how content + agents are ARRANGED
 * 
 * Drawers can be:
 * - Static: defined at configuration time and persisted
 * - Dynamic: computed per prompt/content by Aigent Z and updated on-the-fly
 */

import type { ContentModality } from './smartContent';
import type { DrawerSize, SmartMenuBehavior } from '@/ui/smartLayout/types';

// =============================================================================
// CORE TYPES
// =============================================================================

/** Device types for responsive rendering */
export type Device = 'mobile' | 'desktop' | 'tv';

/** Modality alias for drawer context */
export type Modality = ContentModality;

/** Dynamic mode for drawer sets */
export type DynamicMode = 'static-only' | 'allow-dynamic' | 'dynamic-by-default';

/** Drawer side position */
export type DrawerSide = 'left' | 'right';

/** Agent panel mode */
export type AgentPanelMode = 'copilot' | 'franchise' | 'hybrid';

// =============================================================================
// DRAWER SET - TOP LEVEL
// =============================================================================

/**
 * DrawerSet - All drawers for a given tenant/app/persona
 */
export interface DrawerSet {
  /** Unique ID (e.g., "ds:metaknyts:tenant-main:persona-metaknyts") */
  id: string;

  /** Application context (e.g., "metaKnyts", "Qriptopian") */
  appId: string;

  /** Tenant context */
  tenantId: string;

  /** Persona context (DIDQube persona) */
  personaId: string;

  /** All drawers in this set */
  drawers: Drawer[];

  /** Dynamic mode configuration */
  dynamicMode?: DynamicMode;

  /** Created timestamp */
  createdAt?: string;

  /** Updated timestamp */
  updatedAt?: string;
}

// =============================================================================
// DRAWER - SINGLE SIDE MENU ITEM
// =============================================================================

/**
 * Drawer - One side menu item ("Story", "Wallet", "Codex", "Agents", etc.)
 */
export interface Drawer {
  /** Drawer ID (e.g., "story", "wallet", "codex", "agents") */
  id: string;

  /** UI label */
  label: string;

  /** Icon identifier (Lucide icon name) */
  icon?: string;

  /** Which side the drawer appears on */
  side?: DrawerSide;

  /** Tabs within this drawer */
  tabs: DrawerTab[];

  /** Visibility rules */
  visibilityRules?: VisibilityRules;

  // =========================================================================
  // LAYOUT PROPERTIES (Smart Triad Orchestration)
  // =========================================================================

  /** Default drawer size (wallet-narrow, wallet-wide, panel-3q, immersive-3q, modal-centered, full-immersive) */
  defaultSize?: DrawerSize;

  /** Menu behavior when this drawer is open */
  defaultMenuBehavior?: SmartMenuBehavior;
}

// =============================================================================
// DRAWER TAB
// =============================================================================

/**
 * DrawerTab - Individual tab in a drawer
 */
export interface DrawerTab {
  /** Tab ID (e.g., "summary", "watch", "tasks") */
  id: string;

  /** UI label */
  label: string;

  /** Modality focus for this tab */
  modalityFocus?: Modality[];

  /** Slots (content areas) in this tab */
  slots: DrawerSlot[];

  /** Agent panel configuration */
  agentPanel?: AgentPanelConfig;

  // =========================================================================
  // LAYOUT OVERRIDES (Smart Triad Orchestration)
  // =========================================================================

  /** Override drawer size for this specific tab */
  sizeOverride?: DrawerSize;

  /** Override menu behavior for this specific tab */
  menuBehaviorOverride?: SmartMenuBehavior;
}

// =============================================================================
// DRAWER SLOT
// =============================================================================

/**
 * DrawerSlot - A layout slot in the tab that renders content using card variants
 */
export interface DrawerSlot {
  /** Slot ID */
  id: string;

  /** Card variant to use (from CardVariantRegistry) */
  cardVariant: string;

  /** Data source for this slot */
  dataSource: SlotDataSource;

  /** Behavioural rules */
  behaviour?: SlotBehaviour;
}

// =============================================================================
// SLOT DATA SOURCE
// =============================================================================

/** DeFi position status filter */
export type DefiPositionStatusFilter = 'open' | 'closed' | 'pending';

/** DeFi strategy status filter */
export type DefiStrategyStatusFilter = 'idle' | 'running' | 'cooldown';

/** DeFi strategy category filter */
export type DefiStrategyCategoryFilter = 'yield' | 'marketNeutral' | 'directional' | 'hedging' | 'index';

/** Risk band filter */
export type RiskBandFilter = 'low' | 'medium' | 'high' | 'experimental';

/**
 * SlotDataSource - How a slot knows what to show
 * Supports content, wallet, and DeFi data sources
 */
export type SlotDataSource =
  // Content sources
  | { type: 'currentContent'; modalities?: Modality[] }
  | { type: 'relatedContent'; relationType: RelationType; limit?: number }
  | { type: 'library'; scope: LibraryScope; limit?: number }
  | { type: 'recommended'; strategy: RecommendationStrategy; limit?: number }
  | { type: 'customQuery'; queryId: string }
  // Wallet sources
  | { type: 'walletBalances'; assetFilter?: string[] }
  | { type: 'walletEntitlements'; categoryFilter?: string[]; statusFilter?: string[] }
  | { type: 'walletTasks'; statusFilter?: string[]; contextFilter?: string }
  | { type: 'walletQuests'; statusFilter?: string[]; contextFilter?: string }
  // DeFi portfolio sources (MoneyPenny)
  | { type: 'walletDefiPositions'; statusFilter?: DefiPositionStatusFilter[]; riskFilter?: RiskBandFilter[] }
  | { type: 'walletDefiStrategies'; statusFilter?: DefiStrategyStatusFilter[]; categoryFilter?: DefiStrategyCategoryFilter[] }
  | { type: 'walletDefiRiskSummary' }
  // Agent panel source
  | { type: 'agentPanel'; primaryAgentId?: string; secondaryAgentIds?: string[] };

/** Relation types for content */
export type RelationType = 'series' | 'issue' | 'topic' | 'questPath' | 'strategy' | 'education' | 'mythos';

/** Library scope */
export type LibraryScope = 'owned' | 'recent' | 'wishlist';

/** Recommendation strategy */
export type RecommendationStrategy = 'trending' | 'forPersona' | 'forAgentContext';

// =============================================================================
// SLOT BEHAVIOUR
// =============================================================================

/**
 * SlotBehaviour - Behavioural rules for a slot
 */
export interface SlotBehaviour {
  /** Refresh when current content changes */
  refreshOnContentChange?: boolean;

  /** Refresh when user prompt changes (for dynamic drawers) */
  refreshOnPromptChange?: boolean;

  /** Allow Copilot to dynamically reconfigure this slot */
  dynamicReconfigureAllowed?: boolean;

  /** Visible on specific devices only */
  visibleOnDevices?: Device[];
}

// =============================================================================
// AGENT PANEL CONFIG
// =============================================================================

/**
 * AgentPanelConfig - Agent/metavatar configuration for a tab
 */
export interface AgentPanelConfig {
  /** Panel mode */
  mode: AgentPanelMode;

  /** Primary agent ID (e.g., "Kn0w1", "MoneyPenny", "Nakamoto", "Copilot") */
  primaryAgentId?: string;

  /** Secondary agents */
  secondaryAgents?: string[];

  /** Metavatar ID for visual rendering */
  metavatarId?: string;

  /** Should the panel be open by default */
  openByDefault?: boolean;
}

// =============================================================================
// VISIBILITY RULES
// =============================================================================

/**
 * VisibilityRules - Controls for drawers/tabs based on persona, agent, context
 */
export interface VisibilityRules {
  /** Allowed persona IDs */
  allowedPersonas?: string[];

  /** Allowed agent IDs */
  allowedAgents?: string[];

  /** Minimum reputation score required */
  minReputationScore?: number;

  /** Requires paid entitlement */
  requirePaidEntitlement?: boolean;
}

// =============================================================================
// DRAWER SESSION (FOR DYNAMIC UPDATES)
// =============================================================================

/** Added tab with context */
export interface SessionAddedTab {
  drawerId: string;
  tabId: string;
  tab: DrawerTab;
}

/** Added slot with context */
export interface SessionAddedSlot {
  drawerId: string;
  tabId: string;
  slotId: string;
  slot: DrawerSlot;
}

/** Updated slot with context */
export interface SessionUpdatedSlot {
  drawerId: string;
  tabId: string;
  slotId: string;
  updates: Partial<DrawerSlot>;
}

/** Session overlay for tracking changes */
export interface SessionOverlay {
  addedDrawers?: Drawer[];
  removedDrawerIds?: string[];
  modifiedDrawers?: Partial<Drawer>[];
  addedTabs?: SessionAddedTab[];
  addedSlots?: SessionAddedSlot[];
  updatedSlots?: SessionUpdatedSlot[];
}

/**
 * DrawerSession - Persisted session overlay for dynamic drawer updates
 * Used for Copilot training and refinement
 */
export interface DrawerSession {
  /** Session ID */
  id: string;

  /** Reference to base drawer set */
  drawerSetId: string;

  /** Session identifier */
  sessionId: string;

  /** Persona ID */
  personaId: string;

  /** Prompt context that triggered this configuration */
  promptContext?: string;

  /** Overlay changes */
  overlay: SessionOverlay;

  /** Effectiveness score (for training feedback) */
  effectivenessScore?: number;

  /** Created timestamp */
  createdAt: string;
}

// =============================================================================
// DRAWER CONTEXT (FOR RENDERING)
// =============================================================================

/**
 * DrawerContext - Context passed to drawer renderer
 */
export interface DrawerContext {
  /** Current app */
  appId: string;

  /** Current tenant */
  tenantId: string;

  /** Current persona */
  personaId: string;

  /** Current device */
  device: Device;

  /** Current content ID (if viewing content) */
  currentContentId?: string;

  /** Current agent ID (if interacting with agent) */
  currentAgentId?: string;

  /** User's reputation score */
  reputationScore?: number;

  /** User's entitlement IDs */
  entitlementIds?: string[];
}

// =============================================================================
// FACTORY FUNCTIONS
// =============================================================================

/** Create a new DrawerSet with minimal required fields */
export function createDrawerSet(
  partial: Partial<DrawerSet> & Pick<DrawerSet, 'id' | 'appId' | 'tenantId' | 'personaId'>
): DrawerSet {
  const now = new Date().toISOString();
  return {
    drawers: [],
    dynamicMode: 'static-only',
    createdAt: now,
    updatedAt: now,
    ...partial,
  };
}

/** Create a new Drawer with minimal required fields */
export function createDrawer(
  partial: Partial<Drawer> & Pick<Drawer, 'id' | 'label'>
): Drawer {
  return {
    tabs: [],
    side: 'left',
    ...partial,
  };
}

/** Create a new DrawerTab with minimal required fields */
export function createDrawerTab(
  partial: Partial<DrawerTab> & Pick<DrawerTab, 'id' | 'label'>
): DrawerTab {
  return {
    slots: [],
    ...partial,
  };
}

/** Create a new DrawerSlot with minimal required fields */
export function createDrawerSlot(
  partial: Partial<DrawerSlot> & Pick<DrawerSlot, 'id' | 'cardVariant' | 'dataSource'>
): DrawerSlot {
  return {
    behaviour: {
      refreshOnContentChange: true,
      visibleOnDevices: ['mobile', 'desktop', 'tv'],
    },
    ...partial,
  };
}

/**
 * Smart Layout System - Core Types
 * 
 * Defines drawer sizes, menu behaviors, and layout primitives
 * for the Smart Triad orchestration system.
 */

import { ReactNode } from "react";

/**
 * Drawer size variants
 * 
 * Six layout modes for different interaction contexts:
 * 
 * @wallet-narrow - ~360px slim right panel for quick wallet glances
 * @wallet-wide - ~640px wider panel for wallet + Copilot/SmartTriad  
 * @panel-3q - ~75vw right-anchored content canvas (Qriptopian Scrolls, Kn0wdZ)
 *            Menu remains visible on the right
 * @immersive-3q - Hero + feed layout (metaKnyts episodes with carousel underneath)
 * @modal-centered - Centered 3/4 overlay that sits ABOVE menu (MoneyPenny Portfolio, MetaVatar)
 *                  Menu hidden behind for immersive focus
 * @full-immersive - Fullscreen overlay (cinema, motion comics, gaming)
 */
export type DrawerSize =
  | "wallet-narrow"
  | "wallet-wide"
  | "panel-3q"
  | "immersive-3q"
  | "modal-centered"
  | "full-immersive";

/**
 * Smart Menu behavior modes
 * 
 * @fixed-rail - Always visible vertical rail (Qriptopian default)
 * @floating-rail - Floats above content with glassmorphism
 * @collapsed-pill - Single icon that expands on hover/tap
 * @auto-hide - Hides after inactivity, reappears on edge hover
 */
export type MenuMode =
  | "fixed-rail"
  | "floating-rail"
  | "collapsed-pill"
  | "auto-hide";

/**
 * Smart Menu behavior configuration
 */
export interface SmartMenuBehavior {
  /** Display mode */
  mode: MenuMode;

  /** Side placement (metaKnyts=left, Qriptopian/MoneyPenny=right) */
  side?: "left" | "right";

  /** Auto-hide delay in milliseconds */
  autoHideAfterMs?: number;

  /** Show when cursor approaches edge */
  showOnMoveEdge?: boolean;

  /** Mobile-specific placement */
  mobilePlacement?: "bottom" | "right" | "hidden-until-tap";
}

/**
 * Smart Menu item definition
 */
export interface SmartMenuItem {
  id: string;
  icon: ReactNode;
  label: string;
  tooltip?: string;
  badge?: string | number;
  disabled?: boolean;
}

/**
 * Z-index constants for proper layering
 */
export const SMART_LAYOUT_Z_INDEX = {
  /** Top header */
  HEADER: 40,

  /** Backdrop for drawers */
  BACKDROP: 40,

  /** Standard drawers (wallet, panel-3q, immersive-3q) */
  DRAWER: 50,

  /** Menu rail (sits above standard drawers) */
  MENU_RAIL: 50,

  /** Mobile nav backdrop */
  MOBILE_BACKDROP: 60,

  /** Centered modals (above menu) */
  MODAL_CENTERED: 60,

  /** Mobile nav */
  MOBILE_NAV: 70,

  /** Fullscreen overlays (cinema, metaAvatar) */
  FULL_IMMERSIVE: 100,
} as const;

/**
 * Responsive breakpoints (Tailwind defaults)
 */
export const BREAKPOINTS = {
  mobile: 0,
  tablet: 768,   // md:
  desktop: 1024, // lg:
} as const;

"use client";

import React, { useState, useEffect } from "react";
import { SmartMenuItem, SmartMenuBehavior } from "./types";

export interface SmartMenuRailProps {
  items: SmartMenuItem[];
  activeItemId?: string;
  behavior: SmartMenuBehavior;
  onSelect: (id: string) => void;
  className?: string;
}

export function SmartMenuRail({
  items,
  activeItemId,
  behavior,
  onSelect,
  className = "",
}: SmartMenuRailProps) {
  const [isExpanded, setIsExpanded] = useState(behavior.mode !== "collapsed-pill");
  const [isVisible, setIsVisible] = useState(behavior.mode !== "auto-hide");

  const side = behavior.side || "right";
  const sideClasses = side === "left" ? "left-2 md:left-4" : "right-2 md:right-[2px]";

  // Auto-hide logic
  useEffect(() => {
    if (behavior.mode !== "auto-hide") return;

    let timeout: NodeJS.Timeout;

    const handleActivity = () => {
      setIsVisible(true);
      clearTimeout(timeout);
      timeout = setTimeout(() => {
        setIsVisible(false);
      }, behavior.autoHideAfterMs || 3000);
    };

    window.addEventListener("mousemove", handleActivity);
    window.addEventListener("touchstart", handleActivity);

    return () => {
      clearTimeout(timeout);
      window.removeEventListener("mousemove", handleActivity);
      window.removeEventListener("touchstart", handleActivity);
    };
  }, [behavior.mode, behavior.autoHideAfterMs]);

  // Base button classes
  const buttonClass = (isActive: boolean) => `
    relative w-12 h-12 flex items-center justify-center rounded-lg transition-all
    ${isActive ? "bg-cyan-500/20 text-cyan-400" : "text-white/70 hover:text-cyan-400 hover:bg-cyan-500/10"}
  `;

  // Collapsed pill mode
  if (behavior.mode === "collapsed-pill" && !isExpanded) {
    return (
      <div
        className={`fixed ${sideClasses} top-1/2 -translate-y-1/2 z-50 ${className}`}
        onMouseEnter={() => setIsExpanded(true)}
      >
        <button className="w-12 h-12 rounded-full bg-black/60 backdrop-blur-sm border border-cyan-500/30 flex items-center justify-center text-cyan-400 hover:bg-cyan-500/20 transition-all">
          {items[0]?.icon}
        </button>
      </div>
    );
  }

  // Auto-hide mode
  if (behavior.mode === "auto-hide" && !isVisible) {
    return null;
  }

  // Standard rail layout
  const railClasses = behavior.mode === "floating-rail"
    ? "bg-black/40 backdrop-blur-sm rounded-lg shadow-lg p-1"
    : "";

  return (
    <nav
      className={`hidden md:flex fixed ${sideClasses} top-1/2 -translate-y-1/2 w-14 flex-col items-center py-6 z-50 ${className}`}
      onMouseLeave={() => behavior.mode === "collapsed-pill" && setIsExpanded(false)}
    >
      <div className={`flex flex-col gap-2 ${railClasses}`}>
        {items.map((item) => {
          const isActive = item.id === activeItemId;

          return (
            <button
              key={item.id}
              onClick={() => !item.disabled && onSelect(item.id)}
              className={buttonClass(isActive)}
              title={item.tooltip || item.label}
              disabled={item.disabled}
              aria-label={item.label}
              aria-current={isActive ? "page" : undefined}
            >
              {isActive && (
                <div className="absolute left-0 w-1 h-6 bg-cyan-400 rounded-r" />
              )}
              {item.icon}
              {item.badge && (
                <span className="absolute top-1 right-1 w-4 h-4 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center">
                  {item.badge}
                </span>
              )}
            </button>
          );
        })}
      </div>
    </nav>
  );
}

"use client";

import React from "react";
import { X } from "lucide-react";
import { DrawerSize } from "./types";
import { getDrawerClasses } from "./drawerStyles";

export interface SmartDrawerShellProps {
  isOpen: boolean;
  size: DrawerSize;
  onClose?: () => void;
  title?: string;
  subtitle?: string;
  showHeader?: boolean;
  headerActions?: React.ReactNode;
  heroSlot?: React.ReactNode;
  feedSlot?: React.ReactNode;
  children: React.ReactNode;
  className?: string;
}

export function SmartDrawerShell({
  isOpen,
  size,
  onClose,
  title,
  subtitle,
  showHeader = true,
  headerActions,
  heroSlot,
  feedSlot,
  children,
  className = "",
}: SmartDrawerShellProps) {
  if (!isOpen) return null;

  const isModalCentered = size === "modal-centered";
  const isImmersive3q = size === "immersive-3q";
  const isFullImmersive = size === "full-immersive";

  const drawerContent = (
    <>
      {showHeader && (title || onClose) && (
        <div className="flex-shrink-0 border-b border-border/30 bg-background/60 backdrop-blur-sm px-4 md:px-6 py-4 md:py-6">
          <div className="flex items-start justify-between">
            <div>
              {title && <h2 id="drawer-title" className="text-xl md:text-2xl font-bold">{title}</h2>}
              {subtitle && <p className="text-sm text-muted-foreground mt-1">{subtitle}</p>}
            </div>
            <div className="flex items-center gap-2">
              {headerActions}
              {onClose && (
                <button
                  onClick={onClose}
                  className="p-2 rounded-lg hover:bg-white/10 transition-colors"
                  aria-label="Close"
                >
                  <X className="w-5 h-5" />
                </button>
              )}
            </div>
          </div>
        </div>
      )}

      {isImmersive3q && heroSlot ? (
        <div className="flex flex-col h-full overflow-hidden">
          <div className="flex-shrink-0 min-h-[60vh] relative">{heroSlot}</div>
          <div className="flex-1 overflow-y-auto p-4 md:p-6">{feedSlot || children}</div>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto p-4 md:p-6">{children}</div>
      )}
    </>
  );

  return (
    <>
      {!isFullImmersive && (
        <div
          className="fixed inset-0 bg-black/30 backdrop-blur-sm z-40"
          onClick={onClose}
        />
      )}

      <div className={`${getDrawerClasses(size)} ${className}`}>
        {isModalCentered ? (
          <div className="bg-background/95 backdrop-blur-xl rounded-2xl border border-border/30 shadow-2xl w-full max-w-6xl max-h-[90vh] flex flex-col overflow-hidden">
            {drawerContent}
          </div>
        ) : (
          drawerContent
        )}
      </div>
    </>
  );
}

/**
 * Menu Service - Manages menu configuration and state
 */

import type {
  SmartMenuConfig,
  MenuItem,
  MenuSection,
  MenuState,
  MenuStateDelta,
  MenuContext,
  MenuVisibilityRules,
} from '@/types/smartMenu';

export function evaluateMenuVisibility(
  rules: MenuVisibilityRules | undefined,
  context: MenuContext
): boolean {
  if (!rules) return true;
  if (rules.allowedPersonas?.length && !rules.allowedPersonas.includes(context.personaId)) return false;
  if (rules.requiresAuth && context.identityState === 'anon') return false;
  if (rules.minReputationScore && (context.reputationScore || 0) < rules.minReputationScore) return false;
  if (rules.hideOnMobile && context.deviceType === 'mobile') return false;
  if (rules.hideOnDesktop && context.deviceType === 'desktop') return false;
  return true;
}

export function filterVisibleItems(items: MenuItem[], context: MenuContext): MenuItem[] {
  return items
    .filter(item => evaluateMenuVisibility(item.visibilityRules, context))
    .map(item => ({ ...item, children: item.children ? filterVisibleItems(item.children, context) : undefined }));
}

export function filterVisibleSections(sections: MenuSection[], context: MenuContext): MenuSection[] {
  return sections
    .filter(s => evaluateMenuVisibility(s.visibilityRules, context))
    .map(s => ({ ...s, items: filterVisibleItems(s.items, context) }))
    .filter(s => s.items.length > 0);
}

export function createInitialMenuState(config: SmartMenuConfig): MenuState {
  return {
    expandedSections: [],
    openDrawerIds: config.drawerOrder?.slice(0, 1) || [],
    focusedDrawerId: config.drawerOrder?.[0],
  };
}

export function applyMenuStateDelta(state: MenuState, delta: MenuStateDelta): MenuState {
  return { ...state, ...delta };
}

export function toggleDrawer(state: MenuState, drawerId: string): MenuState {
  const isOpen = state.openDrawerIds.includes(drawerId);
  return {
    ...state,
    openDrawerIds: isOpen ? state.openDrawerIds.filter(id => id !== drawerId) : [...state.openDrawerIds, drawerId],
    focusedDrawerId: isOpen ? state.focusedDrawerId : drawerId,
  };
}

